Feel free to make the changes. I have been looking for other alternatives. Sometimes I also need to exclude some dates. Here is another possible solution for wrapping and skipping events

```python
from dateutil.rrule import *
from dateutil.parser import *
from datetime import *

class CustomEventWrapper(object):
    def __init__(self, event_data):
        self.event_data = event_data

    def __call__(self, date):
        return {'title': self.event_data.get('title', None), 'date': date}


class WrappedRRule(rrule):
    def __init__(self, wrapper, *args, **kwargs):
        super().__init__(*args, **kwargs)
        self.wrapper = wrapper

    def __iter__(self):
        self._my_iter = super().__iter__()
        return self

    def __next__(self):
        value = next(self._my_iter)
        return self.wrapper(value)

class SkippingRRule(rrule):
    def __init__(self, wrapper, *args, exc=[], **kwargs):
        super().__init__(*args, **kwargs)
        self.wrapper = wrapper
        self.exc = exc

    def __iter__(self):
        self._my_iter = enumerate(super().__iter__())
        return self

    def __next__(self):
        i, value = next(self._my_iter)
        while i in self.exc:
            i, value = next(self._my_iter)
        return self.wrapper(value)


wrapper = CustomEventWrapper({'title': 'new event'})
r1 = WrappedRRule(wrapper, DAILY, count=10, dtstart=parse("19970902T090000"))
r2 = SkippingRRule(wrapper, DAILY, count=10, dtstart=parse("19970902T090000"), exc=[2, 3])
```

